-- Reflect FULL template coverage: all 59 ND3 columns are now populated across the suite
-- (was 26/59 — 4-year comp history, HSA, PTO, overtime, waive reason and rehire dates were blank).
update public.protected_content
set payload = jsonb_set(
      jsonb_set(payload, '{datasetMeta,coverage}', to_jsonb(
        '300-employee sweep across 285 counties / 45 states. All 59 ND3 template columns are populated across the suite (4-year comp history, HSA/FSA, PTO, overtime, waive reason, termination/rehire) — so the census is a faithful client shape, not a thin subset.'::text)),
      '{datasetMeta,source}', to_jsonb(
        'backend/scripts/gen_test_datasets.py + scripts/warehouse_ref.py · 352 rows across 8 datasets · 59/59 template columns'::text)),
    updated_at = now()
where key = 'dataset_catalog';
